{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a constrained optimization task involving graph embedding and spatial packing. I will decompose it into a constraint modeling phase and a search/optimization phase.",
  "helpers": [
    {
      "label": "constraint_extractor",
      "instructions": "Identify and model all input data points including the city map structure, the specific color-adjacency requirements, and the connectivity constraints. Define the grid dimensions (50x50) and the objective function (maximize empty cells E, where score is E + 1). Represent the input as a graph where nodes are colors/regions and edges represent required adjacencies, noting any specific topological constraints that must be preserved during the mapping."
    },
    {
      "label": "optimization_engine",
      "instructions": "Implement an algorithm to embed the extracted graph onto the 50x50 grid. The algorithm must place colors such that all adjacency and connectivity constraints are satisfied while minimizing the total number of occupied cells to maximize empty space. Consider approaches such as simulated annealing, backtracking with pruning, or a greedy placement strategy with local search to find a compact layout that respects the topological map requirements."
    }
  ],
  "synthesis_brief": "Combine the formal graph model from the first helper with the optimized grid layout from the second helper. Verify that the resulting grid satisfies all adjacency constraints and calculate the final score based on the number of empty cells."
}

